// Filtros do Licita Já. Aceita body { date (YYYYmmdd), keyword, state, page,
// maxPages } no pull manual; no cron usa a data de hoje (data de catalogação)
// e as configurações de palavras-chave/estados salvas NA CONTA Licita Já
// (quando keyword/state ficam vazios, a API usa o perfil do cliente).
const body = ($input.first().json && ($input.first().json.body ?? $input.first().json)) || {};
const d = new Date();
const pad = (n) => String(n).padStart(2, '0');
const today = `${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}`;
return {
  date: body.date || today,
  keyword: body.keyword || '',
  state: body.state || '',
  page: Number(body.page ?? 1) || 1,
  maxPages: Number(body.maxPages ?? 6) || 6
};

// Quebra a lista de licitações (results) em itens individuais e codifica em
// base64 (passagem segura de JSON para o SQL — sem risco de injeção).
const resp = $input.first().json || {};
const list = resp.results || resp.body?.results || [];
const batchId = $('Create Batch').first().json.batch_id;
if (!Array.isArray(list) || list.length === 0) {
  return [];
}
return list.map((t) => ({
  json: {
    b64: Buffer.from(JSON.stringify(t), 'utf8').toString('base64'),
    batch_id: batchId,
    tenderId: t.tenderId || null
  }
}));

// Paginação: a resposta traz { page, total_results }. Cada página tem até 25
// resultados. Continua até cobrir total_results ou atingir maxPages
// (limite da API Licita Já: 10 requisições/minuto).
const resp = $input.first().json || {};
const base = $('Create Batch').first().json;
const cur = Number(resp.page || base.page || 1);
const total = Number(resp.total_results || 0);
const maxPages = Number(base.maxPages || 6);
const hasNext = cur * 25 < total && cur < maxPages;
if (!hasNext) return [];
return [{ json: { ...base, page: cur + 1 } }];
